# validate_model_card.py — checks model card JSON for completeness

import json, sys
from pathlib import Path

REQUIRED_SECTIONS = [
    "model_identity",
    "intended_use",
    "evaluation",
    "human_oversight",
    "last_review_date",
    "next_review_date",
]

REQUIRED_EVAL_FIELDS = ["accuracy", "hallucination_rate", "bias_score"]

def validate_model_card(path: str) -> list[str]:
    card = json.loads(Path(path).read_text())
    issues = []

    for section in REQUIRED_SECTIONS:
        if section not in card:
            issues.append(f"Missing required section: {section}")

    if "evaluation" in card:
        for field in REQUIRED_EVAL_FIELDS:
            if field not in card["evaluation"]:
                issues.append(f"Missing evaluation metric: {field}")
            elif not card["evaluation"][field].get("pass"):
                issues.append(f"Evaluation metric FAILED: {field} = {card['evaluation'][field].get('result')}")

    if "human_oversight" in card:
        if card["human_oversight"].get("review_rate_target", 1.0) < 1.0:
            if card["human_oversight"].get("oversight_level") == "full":
                issues.append("Inconsistency: oversight_level=full but review_rate_target < 1.0")

    return issues

if __name__ == "__main__":
    path = sys.argv[1] if len(sys.argv) > 1 else "model-card.json"
    issues = validate_model_card(path)
    if issues:
        print(f"Model card validation FAILED ({len(issues)} issues):")
        for issue in issues:
            print(f"  - {issue}")
        sys.exit(1)
    else:
        print(f"Model card validation PASSED: {path}")
